using NP std;
NP phigrOS
{
    il ll read()
    {
        ll x=0,f=1;char ch=gc();
        wh(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
        wh(ch>='0'&&ch<='9'){x=x*10+ch-'0';ch=gc();}
        return x*f;
    }
    void write(ll x)
    {
        if(x<0)pc('-'),x=-x;
        if(x>9)write(x/10);
        pc(x%10+'0');
    }
    void writeln(ll x)
    {
        write(x);
        puts("");
        return;
    }
}
using NP phigrOS;
CI MAXN=2e4+5;
int fa[MAXN],m,n,s,t,ans=0;
struct road
{
    int x,y,w;
    bool operator < (const road &a) const
    {
        return w<a.w;
    }
}a[MAXN];
void init()
{
    FOR(i,1,n)
    {
        fa[i]=i;
    }
}
int find(int x) 
{
	if(fa[x]==x)return x;
	return fa[x]=find(fa[x]);
}
signed main(void)
{
	n=read(),m=read(),s=read(),t=read();
    init();
	FOR(i,1,m)
    {
        a[i].x=read(),a[i].y=read(),a[i].w=read();
    }
    sort(a+1,a+m+1);
    FOR(i,1,m)
    {   
        int fx=find(a[i].x);
	    int fy=find(a[i].y);
        if(fx!=fy)
        {
            fa[fx]=fy;
            ans+=a[i].w;
        }
        if(find(s)==find(t))
        {
            write(a[i].w);
            exit(false);
        }

    }
    write(ans);
    return false;
}
